$$, $$bafac490d56b318376016730bbf8af4dfeb895fb6cc3477b8e7a55dac93103aa$$, $${"A": "573c0b6c5226add3c77d6c7eae936271ae5687f82d042f7414467d87ce417d82", "D": "d4fdf923ba776b98bda680220afe7660b2fb7f78e25f4cb026ad0b29031d9620", "E": "7f2dc7cea1586270f465d803297a2012ef443b5079cd17e26fd74615727dcaca"}$$::jsonb, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume I.pdf$$, 245, $$2026-05-07T23:10:02.989896+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.pe_narratives (pe_id, fiscal_year, mission_description, justification, accomplishments, planned_program, performance_metrics, other_program_funding, raw_text, content_hash, section_hashes, source_pdf, source_page, ingested_at) VALUES ($$0602336F$$, 2027, $$The Nuclear Delivery Systems (NDS) Technology Exploration program establishes the foundational computational tools necessary to conduct nuclear forensics,
perform strategic surveillance, and predict future nuclear re-entry system environmental requirements, effects, and responses. Program activities aid investigations
and analyses of 1) enhanced terminal performance options; 2) national strategic and nuclear deterrence operations; 3) potential clandestine nuclear activity; and 4)
multi-physics algorithms to improve accuracy in simulating previously untested environmental effects and responses in support of nuclear re-entry systems efforts
under PE 0603273F, Science and Technology (S&T) for Nuclear Re-entry Systems. This program provides applied S&T to augment nuclear deterrence operations by
reestablishing specialized expertise and technologies necessary to address, and respond to, current and emerging multi-peer-contested nuclear environments.

 This program is accomplished by the Air Force Research Laboratory (AFRL). AFRL is focused on high-impact, multi-domain S&T solutions that drive innovation
 now while laying the groundwork for the Air and Space Forces to win the future fight. The AFRL effectively synchronizes the Department of the Air Force (DAF) S&T
 enterprise and workforce to align with the most consequential DAF priorities and accelerate the delivery of game-changing S&T.

 This program further supports the requisite DAF science and engineering (S&E) and mission enabling civilian workforce with the necessary technical competencies to
 develop, manage, and deliver S&T capabilities. The use of program funds in this PE is in conjunction with the civilian pay expenses budgeted for in the following PEs:
 1206616SF, 1206601SF, 0601102F, 0602020F, 0602102F, 0602202F, 0602203F, 0602204F, 0602298F, 0602602F, 0602605F, 0602788F, and 0603680F. In FY 2027,
 $1.648 million is budgeted in this program for 8 direct Full-Time Equivalent civilians. AFRL references statutory language under 10 USC 4091 ("Authorities for certain
 positions at S&T reinvention laboratories”) to manage the workforce strength, structure, positions, and compensation.

 To manage, execute, and deliver science and technology capabilities, this Program may include necessary expenses to support the operation and maintenance of
 facilities as well as expenses related to travel, supplies, Information Technology (IT) hardware, software and support, administrative contractor services, etc.

 Funds in this program may be used to investigate specific technological advancements in air, space and/or related cyber domains.

 This program is in Budget Activity 2, Applied Research because this budget activity includes studies, investigations, and non-system specific technology efforts directed
 toward general military needs with a view toward developing and evaluating the feasibility and practicality of proposed solutions and determining their parameters.

